const csvData = $json.data || '';

if (!csvData || csvData.trim().length === 0) {
  console.log('⚠️ No data returned from API');
  return [{ json: { _empty: true } }];
}

// --- CSV parsing helpers ---
function parseCSVLine(line) {
  const vals = [];
  let inQuotes = false;
  let current = '';

  for (let i = 0; i < line.length; i++) {
    const c = line[i];

    if (c === '"' && (i === 0 || line[i - 1] !== '\\')) {
      inQuotes = !inQuotes;
      continue;
    }

    if (c === ',' && !inQuotes) {
      vals.push(current);
      current = '';
      continue;
    }

    current += c;
  }

  vals.push(current);
  return vals.map(v => v.trim());
}

// --- Parse CSV ---
const lines = csvData.trim().split(/\r?\n/);
const headers = parseCSVLine(lines[0]);

console.log('📊 Headers:', headers);

// --- Build account objects ---
const parsedAccounts = [];

for (let i = 1; i < lines.length; i++) {
  const vals = parseCSVLine(lines[i]);
  if (vals.length !== headers.length) continue;

  const account = {};
  headers.forEach((h, idx) => {
    account[h] = vals[idx] || '';
  });

  parsedAccounts.push(account);
}

console.log(`✅ Parsed ${parsedAccounts.length} accounts from CSV`);

// --- Output ---
if (parsedAccounts.length === 0) {
  console.log('⚠️ No accounts parsed - returning empty sentinel');
  return [{ json: { _empty: true } }];
}
return parsedAccounts.map(a => ({ json: a }));

/**
 * Extract Account Data - Run Once for All Items
 * Extracts and normalizes account fields from CSV headers into structured objects.
 */

const items = $input.all();

if (items.length === 0 || (items.length === 1 && items[0].json._empty)) {
  console.log('⚠️ No account data to extract - passing through empty');
  return [{ json: { _empty: true } }];
}
console.log(`🔍 Extract Account Data: Processing ${items.length} items`);

function findHeader(obj, keywords) {
  const keys = Object.keys(obj);
  for (const keyword of keywords) {
    const found = keys.find(k => 
      k.toLowerCase().includes(keyword.toLowerCase())
    );
    if (found) return found;
  }
  return null;
}

function toNumber(x) {
  const n = Number(String(x || '').replace(/[,$]/g, ''));
  return Number.isFinite(n) ? n : 0;
}

const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i].json;

  if (i === 0) {
    console.log('📋 Available keys:', Object.keys(item).join(', '));
  }

  const accountId = item['Account ID'] || item.ootb_account_id || 'Unknown';
  const accountName = item['Account Name'] || item.ootb_account_name || 'Unknown';
  const accountOwner = item['Account Owner (name)'] || item.ootb_account_original_owner || 'Unassigned';
  const accountDomain = item['Account Domain'] || item.ootb_account_domain || '';
  const engagementLevel = toNumber(item['Account Engagement Level'] || item.ootb_account_engagement_level);
  const peopleaiId = item['People.ai Internal ID'] || item.ootb_account_people_internal_id || null;

  // Revenue
  const annualRevenueKey = findHeader(item, ['annual_revenue', 'annual revenue', 'Annual Revenue']);
  const annualRevenue = toNumber(annualRevenueKey ? item[annualRevenueKey] : 0);

  // Meetings
  const meetings7dKey = findHeader(item, ['meetings_standard_last_week', 'Meetings (Last 7 Days)', 'Meetings (Last Week)']);
  const meetings30dKey = findHeader(item, ['meetings_standard_last_30_days', 'Meetings (Last 30 Days)']);
  const meetings7d = toNumber(meetings7dKey ? item[meetings7dKey] : 0);
  const meetings30d = toNumber(meetings30dKey ? item[meetings30dKey] : 0);

  // Emails
  const emails7dKey = findHeader(item, ['emails_last_week', 'Emails (Last 7 Days)', 'Emails (Last Week)']);
  const emails30dKey = findHeader(item, ['emails_last_30_days', 'Emails (Last 30 Days)']);
  const emails7d = toNumber(emails7dKey ? item[emails7dKey] : 0);
  const emails30d = toNumber(emails30dKey ? item[emails30dKey] : 0);

  // People contacted
  const externalPeopleKey = findHeader(item, ['external_people_contacted_last_30', 'External People Contacted (Last 30 Days)']);
  const externalPeople30d = toNumber(externalPeopleKey ? item[externalPeopleKey] : 0);

  // Engaged executives
  const engagedExecsKey = findHeader(item, ['engaged_executives_external_last_30', 'Engaged Executives (Last 30 Days)']);
  const engagedExecs30d = toNumber(engagedExecsKey ? item[engagedExecsKey] : 0);

  if (i < 3) {
    console.log(`✅ Account ${i}: "${accountName}" Owner: "${accountOwner}" Engagement: ${engagementLevel} Revenue: ${annualRevenue} Meetings7d: ${meetings7d} Meetings30d: ${meetings30d}`);
  }

  results.push({
    json: {
      accountId,
      accountName,
      accountOwner,
      accountDomain,
      engagementLevel,
      peopleaiId,
      annualRevenue,
      meetings7d,
      meetings30d,
      emails7d,
      emails30d,
      externalPeople30d,
      engagedExecs30d,
      raw: item
    }
  });
}

console.log(`✅ Extracted ${results.length} accounts with full metrics`);

return results;

/**
 * Filter for Neglected Accounts
 * Criteria: engagement < 30 AND meetings_last_30_days <= 1
 * Sort by annual_revenue descending, take top 10
 */

const items = $input.all();

if (items.length === 0 || (items.length === 1 && items[0].json._empty)) {
  console.log('⚠️ No account data for neglected filter');
  return [{ json: { _empty: true } }];
}

console.log(`🔍 Filtering for neglected accounts from ${items.length} total`);

const filtered = items.filter(item => {
  const eng = item.json.engagementLevel || 0;
  const meetings30d = item.json.meetings30d || 0;
  return eng < 30 && meetings30d <= 1;
});

console.log(`🚨 Found ${filtered.length} neglected accounts (engagement < 30, meetings <= 1)`);

// Sort by annual revenue descending
filtered.sort((a, b) => (b.json.annualRevenue || 0) - (a.json.annualRevenue || 0));

// Take top 10
const top10 = filtered.slice(0, 10);

console.log(`✅ Taking top ${top10.length} neglected accounts by annual revenue`);
top10.forEach((item, idx) => {
  console.log(`  ${idx + 1}. ${item.json.accountName} - Revenue: $${(item.json.annualRevenue || 0).toLocaleString()} - Engagement: ${item.json.engagementLevel}%`);
});

if (top10.length === 0) {
  return [{ json: { _empty: true } }];
}

return top10;

/**
 * Filter for Surging Accounts
 * Criteria: engagement >= 50 AND (meetings_7d / meetings_30d) > 0.4 (accelerating)
 * Sort by engagement descending, take top 10
 */

const items = $input.all();

if (items.length === 0 || (items.length === 1 && items[0].json._empty)) {
  console.log('⚠️ No account data for surging filter');
  return [{ json: { _empty: true } }];
}

console.log(`🔍 Filtering for surging accounts from ${items.length} total`);

const filtered = items.filter(item => {
  const eng = item.json.engagementLevel || 0;
  const meetings7d = item.json.meetings7d || 0;
  const meetings30d = item.json.meetings30d || 0;

  if (eng < 50) return false;
  if (meetings30d === 0) return false;

  const ratio = meetings7d / meetings30d;
  return ratio > 0.4;
});

console.log(`📈 Found ${filtered.length} surging accounts (engagement >= 50, meeting acceleration > 0.4)`);

// Sort by engagement descending
filtered.sort((a, b) => (b.json.engagementLevel || 0) - (a.json.engagementLevel || 0));

// Take top 10
const top10 = filtered.slice(0, 10);

console.log(`✅ Taking top ${top10.length} surging accounts by engagement`);
top10.forEach((item, idx) => {
  const ratio = item.json.meetings30d > 0 ? (item.json.meetings7d / item.json.meetings30d).toFixed(2) : 0;
  console.log(`  ${idx + 1}. ${item.json.accountName} - Engagement: ${item.json.engagementLevel}% - Acceleration: ${ratio}`);
});

if (top10.length === 0) {
  return [{ json: { _empty: true } }];
}

return top10;

/**
 * Filter for Expansion Candidates
 * Criteria: engagement >= 60 AND external_people_contacted_30d >= 3 AND engaged_executives_30d >= 1
 * Sort by engagement descending, take top 10
 */

const items = $input.all();

if (items.length === 0 || (items.length === 1 && items[0].json._empty)) {
  console.log('⚠️ No account data for expansion filter');
  return [{ json: { _empty: true } }];
}

console.log(`🔍 Filtering for expansion candidates from ${items.length} total`);

const filtered = items.filter(item => {
  const eng = item.json.engagementLevel || 0;
  const externalPeople = item.json.externalPeople30d || 0;
  const engagedExecs = item.json.engagedExecs30d || 0;

  return eng >= 60 && externalPeople >= 3 && engagedExecs >= 1;
});

console.log(`💎 Found ${filtered.length} expansion candidates (engagement >= 60, people >= 3, execs >= 1)`);

// Sort by engagement descending
filtered.sort((a, b) => (b.json.engagementLevel || 0) - (a.json.engagementLevel || 0));

// Take top 10
const top10 = filtered.slice(0, 10);

console.log(`✅ Taking top ${top10.length} expansion candidates by engagement`);
top10.forEach((item, idx) => {
  console.log(`  ${idx + 1}. ${item.json.accountName} - Engagement: ${item.json.engagementLevel}% - People: ${item.json.externalPeople30d} - Execs: ${item.json.engagedExecs30d}`);
});

if (top10.length === 0) {
  return [{ json: { _empty: true } }];
}

return top10;

// Handle empty input
if ($input.all().length === 1 && $input.all()[0].json._empty) {
  return [{ json: { _empty: true } }];
}

const aiOutputs = $input.all();
const originalData = $('Filter Neglected Accounts').all();

console.log(`🔗 Pass Through Neglected: Merging ${aiOutputs.length} AI outputs with ${originalData.length} accounts`);

const results = aiOutputs.map((aiItem, idx) => {
  const original = originalData[idx]?.json || {};
  const aiOutput = aiItem.json.output || aiItem.json.text || aiItem.json.response || JSON.stringify(aiItem.json);

  return {
    json: {
      accountName: original.accountName || 'Unknown',
      accountOwner: original.accountOwner || 'Unassigned',
      accountId: original.accountId,
      engagementLevel: original.engagementLevel,
      peopleaiId: original.peopleaiId,
      annualRevenue: original.annualRevenue,
      meetings7d: original.meetings7d,
      meetings30d: original.meetings30d,
      emails7d: original.emails7d,
      emails30d: original.emails30d,
      output: aiOutput,
      raw: original.raw || original
    }
  };
});

console.log(`✅ Pass Through Neglected complete: ${results.length} items`);
return results;

// Parse Neglected Account AI Response
if ($input.all().length === 1 && $input.all()[0].json._empty) {
  return [{ json: { _empty: true } }];
}

const items = $input.all();
console.log(`🚨 Parse Neglected AI Response: Processing ${items.length} items`);

const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i].json;
  const aiOutput = item.output || '';

  // Extract risk level
  let riskLevel = 'medium';
  const riskMatch = aiOutput.match(/\*\*RISK_LEVEL:\*\*\s*(\w+)/i);
  if (riskMatch) riskLevel = riskMatch[1].toLowerCase().trim();
  else if (/critical/i.test(aiOutput)) riskLevel = 'critical';
  else if (/high.*risk/i.test(aiOutput)) riskLevel = 'high';

  // Extract neglect reason
  let neglectReason = '';
  const reasonMatch = aiOutput.match(/\*\*NEGLECT_REASON:\*\*\s*([^\n]+)/i);
  if (reasonMatch) neglectReason = reasonMatch[1].trim();

  // Extract risks
  const risks = [];
  const risksMatch = aiOutput.match(/\*\*RISKS:\*\*\s*([\s\S]*?)(?=\n\*\*|$)/i);
  if (risksMatch) {
    const bullets = risksMatch[1].split('\n')
      .map(s => s.trim())
      .filter(s => s.startsWith('-') || s.startsWith('•'))
      .map(s => s.replace(/^[-•]\s*/, '').trim());
    risks.push(...bullets);
  }

  // Extract revenue at risk
  let revenueAtRisk = '';
  const revMatch = aiOutput.match(/\*\*REVENUE_AT_RISK:\*\*\s*([^\n]+)/i);
  if (revMatch) revenueAtRisk = revMatch[1].trim();

  // Extract recommendation
  let recommendation = '';
  const recMatch = aiOutput.match(/\*\*RECOMMENDATION:\*\*\s*([^\n]+)/i);
  if (recMatch) recommendation = recMatch[1].trim();

  // Extract confidence
  let confidence = 'medium';
  const confMatch = aiOutput.match(/\*\*CONFIDENCE:\*\*\s*(\w+)/i);
  if (confMatch) confidence = confMatch[1].toLowerCase();

  console.log(`🚨 ${i + 1}: "${item.accountName}" -> risk: ${riskLevel}`);

  results.push({
    json: {
      accountName: item.accountName,
      accountOwner: item.accountOwner,
      accountId: item.accountId,
      engagementLevel: item.engagementLevel,
      peopleaiId: item.peopleaiId,
      annualRevenue: item.annualRevenue,
      meetings7d: item.meetings7d,
      meetings30d: item.meetings30d,
      emails7d: item.emails7d,
      emails30d: item.emails30d,
      riskLevel,
      neglectReason,
      risks,
      revenueAtRisk,
      recommendation,
      confidence,
      context: aiOutput
    }
  });
}

console.log(`✅ Parsed ${results.length} neglected account responses`);
return results;

/**
 * Aggregate Neglected Account Results
 */
const items = $input.all();

if (items.length === 0 || (items.length === 1 && !items[0].json?.accountName && !items[0].json?._empty !== undefined)) {
  console.log('⚠️ No neglected account data to aggregate');
  return [{ json: { neglectedAccounts: [], totalNeglected: 0, _empty: true } }];
}

console.log(`📊 Aggregating ${items.length} neglected account results`);

const neglectedAccounts = [];

items.forEach((item, idx) => {
  const json = item.json;
  if (json._empty) return;
  if (json.accountOwner === 'Unassigned Account') return;

  neglectedAccounts.push({
    accountName: json.accountName || 'Unknown',
    accountOwner: json.accountOwner || 'Unassigned',
    peopleaiId: json.peopleaiId || null,
    engagementLevel: json.engagementLevel || 0,
    annualRevenue: json.annualRevenue || 0,
    meetings30d: json.meetings30d || 0,
    emails30d: json.emails30d || 0,
    riskLevel: json.riskLevel || 'medium',
    neglectReason: json.neglectReason || '',
    revenueAtRisk: json.revenueAtRisk || '',
    recommendation: json.recommendation || '',
    confidence: json.confidence || 'medium'
  });
});

console.log(`✅ Aggregated ${neglectedAccounts.length} neglected accounts`);

return [{ json: { neglectedAccounts, totalNeglected: neglectedAccounts.length } }];

// Handle empty input
if ($input.all().length === 1 && $input.all()[0].json._empty) {
  return [{ json: { _empty: true } }];
}

const aiOutputs = $input.all();
const originalData = $('Filter Surging Accounts').all();

console.log(`🔗 Pass Through Surging: Merging ${aiOutputs.length} AI outputs with ${originalData.length} accounts`);

const results = aiOutputs.map((aiItem, idx) => {
  const original = originalData[idx]?.json || {};
  const aiOutput = aiItem.json.output || aiItem.json.text || aiItem.json.response || JSON.stringify(aiItem.json);

  return {
    json: {
      accountName: original.accountName || 'Unknown',
      accountOwner: original.accountOwner || 'Unassigned',
      accountId: original.accountId,
      engagementLevel: original.engagementLevel,
      peopleaiId: original.peopleaiId,
      meetings7d: original.meetings7d,
      meetings30d: original.meetings30d,
      emails7d: original.emails7d,
      emails30d: original.emails30d,
      externalPeople30d: original.externalPeople30d,
      engagedExecs30d: original.engagedExecs30d,
      output: aiOutput,
      raw: original.raw || original
    }
  };
});

console.log(`✅ Pass Through Surging complete: ${results.length} items`);
return results;

// Parse Surging Account AI Response
if ($input.all().length === 1 && $input.all()[0].json._empty) {
  return [{ json: { _empty: true } }];
}

const items = $input.all();
console.log(`📈 Parse Surging AI Response: Processing ${items.length} items`);

const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i].json;
  const aiOutput = item.output || '';

  // Extract buying signal assessment
  let buyingSignal = 'maybe';
  const sigMatch = aiOutput.match(/\*\*BUYING_SIGNAL:\*\*\s*(\w+)/i);
  if (sigMatch) buyingSignal = sigMatch[1].toLowerCase().trim();

  // Extract surge driver
  let surgeDriver = '';
  const driverMatch = aiOutput.match(/\*\*SURGE_DRIVER:\*\*\s*([^\n]+)/i);
  if (driverMatch) surgeDriver = driverMatch[1].trim();

  // Extract signals
  const signals = [];
  const signalsMatch = aiOutput.match(/\*\*SIGNALS:\*\*\s*([\s\S]*?)(?=\n\*\*|$)/i);
