      html += `<div style="color: #5b21b6; font-size: 13px; font-style: italic; background-color: #f5f3ff; padding: 8px; border-radius: 4px; margin-bottom: 4px;">\ud83d\udca1 ${truncate(acct.expansionSignals, 120)}</div>`;
    }
    if (acct.estimatedValue) {
      html += `<div style="color: #5b21b6; font-size: 13px; font-weight: 600;">\ud83d\udcb0 Est: ${truncate(acct.estimatedValue, 80)}</div>`;
    }
    if (acct.recommendation) {
      html += `<div style="color: #065f46; font-size: 13px;">\u2192 ${truncate(acct.recommendation, 120)}</div>`;
    }
    html += `</td></tr>`;
  });
  html += `</table>`;
} else {
  html += `<p style="color: #6b7280; font-style: italic; margin: 16px 0;">No expansion candidates detected</p>`;
}
html += `</div>`;

// Footer
html += `
    </div>
    <div style="background-color: #f9fafb; padding: 24px 32px; border-top: 1px solid #e5e7eb; text-align: center;">
      <p style="margin: 0 0 8px 0; color: #6b7280; font-size: 13px;">Powered by Account Insights \u2022 People.ai + Claude AI \u2022 ${today}</p>
      <p style="margin: 0; color: #9ca3af; font-size: 12px;">This is an automated digest based on account activity data and AI analysis</p>
    </div>
  </div>
</body>
</html>`;

console.log('\ud83d\udce7 Email HTML formatted:', html.length, 'characters');

return [{
  json: {
    htmlEmail: html,
    subject: `Account Insights Digest - ${today}`,
    today,
    totalNeglected: neglected.length,
    totalSurging: surging.length,
    totalExpansion: expansion.length,
    ...data
  }
}];
